private boolean testAttr(Attr attr) {
    String nodePrefix = DOMNodePointer.getPrefix(attr);
    String nodeLocalName = DOMNodePointer.getLocalName(attr);

    if ((nodePrefix != null && nodePrefix.equals("xmlns")) || (nodePrefix == null && nodeLocalName.equals("xmlns"))) {
        return false;
    }

    String testLocalName = name.getName();
    if (testLocalName.equals("*") || testLocalName.equals(nodeLocalName)) {
        String testPrefix = name.getPrefix();
        if ((testPrefix == null || testPrefix.equals("*") || equalStrings(testPrefix, nodePrefix))) {
            return true;
        }

        // Check namespace only if both prefixes are non-null
        if (testPrefix != null && nodePrefix != null) {
            String testNS = parent.getNamespaceURI(testPrefix);
            String nodeNS = parent.getNamespaceURI(nodePrefix);
            return equalStrings(testNS, nodeNS);
        }
    }
    return false;
}

public JDOMAttributeIterator(NodePointer parent, QName name) {
    this.parent = parent;
    attributes = new ArrayList(); // Initialize as empty list
    if (parent.getNode() instanceof Element) {
        Element element = (Element) parent.getNode();
        String prefix = name.getPrefix();
        Namespace ns = Namespace.NO_NAMESPACE; // Default to NO_NAMESPACE if no prefix or invalid namespace

        if (prefix != null) {
            if (prefix.equals("xml")) {
                ns = Namespace.XML_NAMESPACE;
            } else {
                String uri = parent.getNamespaceResolver().getNamespaceURI(prefix);
                if (uri != null) {
                    ns = Namespace.getNamespace(prefix, uri);
                }
            }
        }

        String lname = name.getName();
        if (!lname.equals("*")) {
            Attribute attr = element.getAttribute(lname, ns);
            if (attr != null) {
                attributes.add(attr);
            }
        } else {
            List allAttributes = element.getAttributes();
            for (Object attribute : allAttributes) {
                Attribute attr = (Attribute) attribute;
                if (ns.equals(Namespace.NO_NAMESPACE) || attr.getNamespace().equals(ns)) {
                    attributes.add(attr);
                }
            }
        }
    }
}

